export const getRoleDashboardConfig = (role) => {
  if (role === 'teacher') {
    return {
      appTitle: 'QuizAtelier',
      systemTagline: 'Teacher Studio',
      roleLabel: 'Teacher',
      menuItems: [
        { id: 'my-quizzes', icon: 'library_books', label: 'My Quizzes', path: '/quizzes/manage' },
        { id: 'students', icon: 'group', label: 'Students' },
        { id: 'analytics', icon: 'analytics', label: 'Analytics' },
        { id: 'history', icon: 'history', label: 'Lịch sử làm bài', path: '/history' },
      ],
    };
  }

  if (role === 'parent') {
    return {
      appTitle: 'QuizAtelier',
      systemTagline: 'Parent Portal',
      roleLabel: 'Parent',
      menuItems: [
        { id: 'progress', icon: 'trending_up', label: 'Tiến độ của con' },
        { id: 'schedule', icon: 'calendar_today', label: 'Lịch học/kiểm tra' },
        { id: 'messages', icon: 'chat', label: 'Tin nhắn với GV' },
        { id: 'resources', icon: 'folder_shared', label: 'Tài liệu hỗ trợ' },
        { id: 'history', icon: 'history', label: 'Lịch sử làm bài', path: '/history' },
      ],
    };
  }

  if (role === 'admin' || role === 'super_admin') {
    return {
      appTitle: 'QuizAtelier',
      systemTagline: 'Super Admin',
      roleLabel: 'Admin',
      menuItems: [
        { id: 'users', icon: 'group', label: 'Người dùng' },
        { id: 'quizzes', icon: 'quiz', label: 'Quản lý Quiz', path: '/quizzes/manage' },
        { id: 'reports', icon: 'bar_chart', label: 'Báo cáo' },
        { id: 'tickets', icon: 'confirmation_number', label: 'Support Tickets' },
        { id: 'history', icon: 'history', label: 'Lịch sử làm bài', path: '/history' },
      ],
    };
  }

  return {
    appTitle: 'QuizAtelier',
    systemTagline: 'Hệ thống học sinh',
    roleLabel: 'Student',
    menuItems: [
      { id: 'tasks', icon: 'assignment', label: 'Bài tập được giao' },
      { id: 'practice', icon: 'fitness_center', label: 'Tự luyện tập', path: '/quizzes/manage' },
      { id: 'achievements', icon: 'military_tech', label: 'Thành tích' },
      { id: 'history', icon: 'history', label: 'Lịch sử làm bài', path: '/history' },
    ],
  };
};

