import React from 'react';
import { QuizApiClient } from '@/infrastructure/quiz/QuizApiClient';
import { getGuestAttemptId } from '@/utils/guestAttemptId';

function fmtDuration(sec) {
  const n = Math.max(0, Number(sec || 0));
  const m = Math.floor(n / 60);
  const s = n % 60;
  return `${m}m ${String(s).padStart(2, '0')}s`;
}

function fmtDate(ts) {
  try {
    return new Date(Number(ts || 0)).toLocaleString();
  } catch {
    return 'N/A';
  }
}

export default function QuizHistoryPage({ session }) {
  const api = React.useMemo(() => new QuizApiClient(), []);
  const token = session?.accessToken || null;
  const guestId = !token ? getGuestAttemptId() : '';
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState('');
  const [items, setItems] = React.useState([]);

  React.useEffect(() => {
    let mounted = true;
    setLoading(true);
    const req = token ? api.getMyQuizResults(token) : guestId ? api.getGuestQuizResults(guestId) : Promise.resolve({ items: [] });
    req
      .then((data) => {
        if (!mounted) return;
        setItems(Array.isArray(data?.items) ? data.items : []);
      })
      .catch((e) => setError(e.message || 'Không tải được lịch sử làm bài.'))
      .finally(() => {
        if (mounted) setLoading(false);
      });
    return () => {
      mounted = false;
    };
  }, [api, token, guestId]);

  return (
    <div className="mx-auto max-w-5xl space-y-6">
      <h1 className="font-headline text-3xl font-extrabold">Lịch sử làm bài</h1>
      {!token && !guestId ? (
        <div className="rounded-2xl border border-amber-200 bg-amber-50 p-5 text-sm text-amber-900">
          Không tìm thấy ID guest trên thiết bị này.
        </div>
      ) : null}
      {loading ? <p className="text-sm text-slate-600">Đang tải dữ liệu...</p> : null}
      {error ? <p className="text-sm font-semibold text-rose-700">{error}</p> : null}
      {!loading && items.length === 0 ? (
        <div className="rounded-2xl border border-slate-100 bg-white p-6 text-sm text-slate-600 shadow-sm">
          Chưa có lịch sử làm bài nào.
        </div>
      ) : null}

      <div className="space-y-3">
        {items.map((row) => (
          <article key={row.id} className="rounded-2xl border border-slate-100 bg-white p-5 shadow-sm">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <h2 className="font-bold text-slate-900">{row.quiz_title || `Quiz ${row.quiz_id}`}</h2>
              <span className="rounded-full bg-cyan-50 px-3 py-1 text-xs font-bold text-cyan-700">
                {row.score}% ({row.correct_answers}/{row.total_questions})
              </span>
            </div>
            <div className="mt-2 grid gap-2 text-sm text-slate-600 md:grid-cols-3">
              <p>Thời điểm: {fmtDate(row.timestamp)}</p>
              <p>Thời gian làm: {fmtDuration(row.time_taken)}</p>
              <p>Mốc đạt: {Number(row.pass_score || 70)}%</p>
            </div>
          </article>
        ))}
      </div>
    </div>
  );
}
