import React, { useMemo, useState } from 'react';
import { createAuthDependencies } from '@/app/auth/createAuthDependencies';

export default function RegisterPage({ onLogin, onRegistered }) {
  const deps = useMemo(() => createAuthDependencies(), []);
  const [role, setRole] = useState('teacher');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const submit = async (event) => {
    event.preventDefault();
    setError('');
    if (!name || !email || !password) {
      setError('Vui lòng nhập đầy đủ họ tên, email và mật khẩu.');
      return;
    }
    setLoading(true);
    try {
      const result = await deps.registerWithEmail.execute({ name, email, password, role });
      onRegistered?.(result, role);
    } catch (e) {
      setError(e.message || 'Đăng ký thất bại.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="min-h-screen bg-sky-50 p-4 md:p-8">
      <div className="mx-auto grid w-full max-w-6xl grid-cols-1 gap-8 lg:grid-cols-12">
        <section className="relative hidden overflow-hidden rounded-3xl bg-emerald-300 p-12 lg:col-span-5 lg:flex lg:flex-col lg:justify-between">
          <div>
            <h1 className="font-headline text-5xl font-extrabold text-emerald-950">Kiến tạo tri thức theo cách của bạn.</h1>
            <p className="mt-6 max-w-md text-emerald-900">Tham gia cộng đồng học tập sáng tạo dành cho giáo viên, phụ huynh và học sinh.</p>
          </div>
          <div className="rounded-2xl border border-white/40 bg-white/40 p-5">
            <p className="text-sm font-bold text-slate-900">Thử thách mới!</p>
            <p className="text-xs text-slate-700">Hoàn thành đăng ký để nhận ngay 500 Atelier Points.</p>
          </div>
        </section>

        <section className="rounded-3xl bg-white p-8 shadow-sm lg:col-span-7 md:p-12">
          <div className="mx-auto w-full max-w-md">
            <h2 className="font-headline text-3xl font-bold text-slate-900">Bắt đầu hành trình</h2>
            <p className="mt-2 text-slate-600">Điền thông tin bên dưới để tạo tài khoản mới.</p>

            <form onSubmit={submit} className="mt-8 space-y-6">
              <div>
                <label className="mb-3 block text-xs font-semibold uppercase tracking-wider text-slate-500">Chọn vai trò của bạn</label>
                <div className="grid grid-cols-3 gap-3">
                  {[
                    { value: 'teacher', label: 'Giáo viên', icon: 'school' },
                    { value: 'student', label: 'Học sinh', icon: 'person_play' },
                    { value: 'parent', label: 'Phụ huynh', icon: 'family_restroom' },
                  ].map((item) => (
                    <button
                      key={item.value}
                      type="button"
                      onClick={() => setRole(item.value)}
                      className={`rounded-xl border-2 p-3 text-center transition ${
                        role === item.value ? 'border-emerald-600 bg-emerald-50' : 'border-transparent bg-slate-50'
                      }`}
                    >
                      <span className="material-symbols-outlined block text-2xl text-emerald-700">{item.icon}</span>
                      <span className="text-xs font-bold">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <label className="block">
                <span className="mb-2 block text-sm font-medium text-slate-700">Họ và tên</span>
                <input value={name} onChange={(e) => setName(e.target.value)} className="w-full rounded-xl border-0 bg-sky-50 px-4 py-3.5 focus:ring-2 focus:ring-emerald-300" placeholder="Nguyễn Văn A" />
              </label>
              <label className="block">
                <span className="mb-2 block text-sm font-medium text-slate-700">Địa chỉ Email</span>
                <input value={email} type="email" onChange={(e) => setEmail(e.target.value)} className="w-full rounded-xl border-0 bg-sky-50 px-4 py-3.5 focus:ring-2 focus:ring-emerald-300" placeholder="example@gmail.com" />
              </label>
              <label className="block">
                <span className="mb-2 block text-sm font-medium text-slate-700">Mật khẩu</span>
                <input value={password} type="password" onChange={(e) => setPassword(e.target.value)} className="w-full rounded-xl border-0 bg-sky-50 px-4 py-3.5 focus:ring-2 focus:ring-emerald-300" placeholder="••••••••" />
              </label>

              {error ? <p className="rounded-xl bg-red-50 px-4 py-3 text-sm text-red-700">{error}</p> : null}

              <button
                disabled={loading}
                className="flex w-full items-center justify-center gap-2 rounded-xl bg-emerald-700 px-6 py-4 text-lg font-bold text-white shadow-lg shadow-emerald-200 transition hover:bg-emerald-800 disabled:opacity-50"
                type="submit"
              >
                {loading ? 'Đang xử lý...' : 'Đăng ký tài khoản'}
                <span className="material-symbols-outlined">arrow_forward</span>
              </button>
            </form>

            <p className="mt-8 text-center text-slate-600">
              Đã có tài khoản?{' '}
              <button onClick={onLogin} className="font-bold text-emerald-700 hover:underline">
                Đăng nhập ngay
              </button>
            </p>
          </div>
        </section>
      </div>
    </main>
  );
}

